        const idSplit = contextIdentifier.toString().split('#');
        this.#contextAlias = idSplit[0];
        this.#apiAlias = idSplit[1] ?? 'default';
        this.#callback = callback;
        this.#discriminator = contextIdentifier.getDiscriminator?.();
